type FieldProps<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = Omit<ControllerProps<TFieldValues, TName>, "render" | "name"> &
  Pick<
    FormItemLabelProps,
    "layout" | "labelAlign" | "labelCol" | "required"
  > & {
    ref?: React.ForwardedRef<HTMLDivElement>;
    name?: ControllerProps<TFieldValues, TName>["name"];
    label?: string | React.JSX.Element;
    description?: React.ReactNode;
    className?: string;
    /* The prompt message. If not provided, the prompt message will be generated by the validation rule. */
    help?:
      | React.ReactNode
      | ((
          ctx: Parameters<ControllerProps<TFieldValues, TName>["render"]>[0],
        ) => React.ReactNode);
    validateStatus?: "success" | "warning" | "error" | "validating";

    /* Props of children node, for example, the prop of Switch or Checkbox is `checked`. This prop is an encapsulation of `getValueProps`, which will be invalid after customizing getValueProps */
    valuePropName?: string;

    /** Additional props with sub component (It's not recommended to generate dynamic function prop by `getValueProps`. Please pass it to child component directly) */
    getValueProps?: (value: any) => Record<string, any>;

    /** Normalize value from component value before passing to Form instance. Do not support async */
    normalize?: (value: any, prevValue: any) => any;

    children?:
      | React.ReactElement
      | ControllerProps<TFieldValues, TName>["render"];

    render?: ControllerProps<TFieldValues, TName>["render"];
  };
const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  control,
  name,

  children,
  render,

  label,

  className,

  help,

  validateStatus,

  required,

  layout,
  labelAlign,
  labelCol,

  normalize,

  getValueProps,
  valuePropName,

  ...props
}: FieldProps<TFieldValues, TName>) => {
  const formContext = useFormContext<TFieldValues, any, TFieldValues>();
  const mergedLayout = layout ?? formContext?.layout;
  const classNames = formContext?.classNames;
  const wrapperCol = formContext?.wrapperCol;

  const requiredChecked = useRequiredFieldCheck(name);
  const mergedRequired = required ?? requiredChecked ?? false;

  // if (render && name) {
  //   return (
  //     <FormFieldContext.Provider value={{ name: name }}>
  //       <Controller name={name} render={render} {...props} />
  //     </FormFieldContext.Provider>
  //   );
  // }
  // if (form && name) {
  //   return (
  //     <FieldController
  //       control={form.control}
  //       name={name}
  //       children={children}
  //       onChange={onChange}
  //       required={isRequired}
  //       layout={layout}
  //       classNames={classNames}
  //       {...props}
  //     />
  //   );
  // }

  // Based on shadcn
  if (render && control && name) {
    return <ShadFormField control={control} name={name} render={render} />;
  }

  const labelNode = label ? (
    <FieldLabel
      className={cn(classNames?.label)}
      required={mergedRequired}
      layout={mergedLayout}
      labelAlign={labelAlign}
      labelCol={labelCol}
    >
      {label}
    </FieldLabel>
  ) : null;

  const finalValuePropName = valuePropName ?? "value";

  if (
    !render &&
    formContext &&
    name &&
    isValidElement<{
      onBlur?: (event: any) => void;
      onChange?: (event: any) => void;
      [key: string]: any;
    }>(children)
  ) {
    return (
      <ShadFormField
        control={control}
        name={name}
        render={(ctx) => {
          const controlContent = (
            <div className="w-full" data-slot="form-item-control">
              <div
                className="flex w-full items-center"
                data-slot="form-item-control-input"
              >
                <FormControl>
                  {cloneElement(children, {
                    ...ctx.field,
                    [finalValuePropName]: ctx.field.value,
                    // Apply getValueProps if provided
                    ...(getValueProps ? getValueProps(ctx.field.value) : {}),
                    onBlur: (event: any) => {
                      children.props.onBlur?.(event);
                      ctx.field.onBlur();
                    },
                    onChange: (event: any) => {
                      children.props.onChange?.(event);

                      const value = event === undefined ? null : event; // fix react-hook-form doesn't support undefined value

                      const normalizedValue = normalize?.(
                        value,
                        ctx.field.value,
                      );

                      ctx.field.onChange(
                        normalize
                          ? normalizedValue === undefined
                            ? null
                            : normalizedValue
                          : value,
                      );
                    },
                  })}
                </FormControl>
              </div>
              <div data-slot="form-item-additional">
                <FieldMessage
                  validateStatus={
                    validateStatus ?? (help ? "default" : undefined)
                  }
                >
                  {typeof help === "function" ? help(ctx) : help}
                </FieldMessage>
              </div>
            </div>
          );

          return (
            <FormItem layout={mergedLayout} className={className} {...props}>
              {labelNode}
              {wrapperCol ? (
                <Col {...wrapperCol}>{controlContent}</Col>
              ) : (
                controlContent
              )}
            </FormItem>
          );
        }}
      />
    );
  }
  // if (nadme) {
  //   return (
  //     <FormFieldContext.Provider
  //       value={{
  //         name,
  //       }}
  //     >
  //       <FormItem {...props}>
  //         {ContentComp}
  //         {/* <FieldRender
  //           children={children}
  //           ref={ref}
  //           required={required}
  //           layout={layout}
  //           classNames={classNames}
  //           {...props}
  //         /> */}
  //       </FormItem>
  //     </FormFieldContext.Provider>
  //   );
  // }

  if (name && typeof children === "function") {
    return (
      <ShadFormField
        control={control}
        name={name}
        render={({ field, fieldState, formState }) => {
          const controlContent = (
            <div className="w-full" data-slot="form-item-control">
              <FormControl>
                {children({ field, fieldState, formState })}
                {/* {cloneElement(children, {
              ...field,
              // value: watchedValue,
              onBlur: (event) => {
                children.props.onBlur?.(event);
                field.onBlur();
              },
              onChange: (event: any) => {
                const value = event === undefined ? null : event; // fix react-hook-form doesn't support undefined value

                const normalizedValue = normalize?.(value, field.value);
                field.onChange(
                  normalize
                    ? normalizedValue === undefined
                      ? null
                      : normalizedValue
                    : value,
                );
              },
            })} */}
              </FormControl>
              <FieldMessage />
            </div>
          );

          return (
            <FormItem layout={mergedLayout} className={className} {...props}>
              {labelNode}
              {wrapperCol ? (
                <Col {...wrapperCol}>{controlContent}</Col>
              ) : (
                controlContent
              )}
            </FormItem>
          );
        }}
      />
    );
  }

  // No control and name
  return (
    <FormItem
      layout={mergedLayout}
      className={cn(!labelNode && "justify-end", className)}
      {...props}
    >
      {labelNode}
      {typeof children === "function" ? (
        <>You should pass name into {"<Field>"}</>
      ) : (
        children
      )}
    </FormItem>
  );
};

